451→    async fn get_devices(&self, user: &str) -> Result<Option<DeviceListRecord>> {
452→        match self
453→            .device_list_records
454→            .get(user.as_bytes())
455→            .map_err(db_err)?
456→        {
457→            Some(v) => Ok(Some(decode_persistent(&v)?)),
458→            None => Ok(None),
459→        }
460→    }
461→
462→    async fn mark_forget_sender_key(&self, group_jid: &str, participant: &str) -> Result<()> {
463→        let key = format!("{group_jid}:{participant}");
464→        self.sender_key_forget_marks
465→            .insert(key.as_bytes(), &[1u8])
466→            .map_err(db_err)?;
467→        Ok(())
468→    }
469→
470→    async fn consume_forget_marks(&self, group_jid: &str) -> Result<Vec<String>> {
471→        let prefix = format!("{group_jid}:");
472→        let mut participants = Vec::new();
473→        let mut keys_to_remove = Vec::new();
474→
475→        for entry in self.sender_key_forget_marks.iter() {
476→            let (k, _) = entry.map_err(db_err)?;
477→            let key_str = String::from_utf8_lossy(&k);
478→            if let Some(participant) = key_str.strip_prefix(&prefix) {
479→                participants.push(participant.to_string());
480→                keys_to_remove.push(k);
481→            }
482→        }
483→        for key in keys_to_remove {
484→            self.sender_key_forget_marks.remove(key).map_err(db_err)?;
485→        }
486→        Ok(participants)
487→    }
488→}
