494→#[async_trait]
495→impl DeviceStore for SledStore {
496→    async fn save(&self, device: &wacore::store::Device) -> Result<()> {
497→        let val = encode_persistent(device)?;
498→        self.device_data
499→            .insert(b"device", val.as_slice())
500→            .map_err(db_err)?;
501→        Ok(())
502→    }
503→
504→    async fn load(&self) -> Result<Option<wacore::store::Device>> {
505→        match self.device_data.get(b"device").map_err(db_err)? {
506→            Some(v) => Ok(Some(decode_persistent(&v)?)),
507→            None => Ok(None),
508→        }
509→    }
510→
511→    async fn exists(&self) -> Result<bool> {
512→        Ok(self.device_data.get(b"device").map_err(db_err)?.is_some())
513→    }
514→
515→    async fn create(&self) -> Result<i32> {
516→        let id = self
517→            .device_id
518→            .fetch_add(1, std::sync::atomic::Ordering::SeqCst);
519→        // Persist the counter.
520→        let tree = self.db.open_tree("device_id").map_err(db_err)?;
521→        tree.insert(b"counter", &(id + 1).to_le_bytes())
522→            .map_err(db_err)?;
523→        Ok(id)
524→    }
525→}
