  1→//! In-memory storage backend for whatsapp-rust.
  2→//!
  3→//! This is a temporary solution while `whatsapp-rust-sqlite-storage` has a
  4→//! `libsqlite3-sys` version conflict with `sqlx`. Session state does NOT
  5→//! persist across restarts — the user must re-scan the QR code.
  6→//!
  7→//! TODO: Replace with `whatsapp-rust-sqlite-storage` once sqlx 0.9 stabilises
  8→//! (it uses a range-based libsqlite3-sys dep that resolves the conflict).
  9→
 10→use std::{fmt::Write, sync::Arc};
 11→
 12→use {
 13→    async_trait::async_trait,
 14→    dashmap::DashMap,
 15→    wacore::{
 16→        appstate::{hash::HashState, processor::AppStateMutationMAC},
 17→        store::{error::Result, traits::*},
 18→    },
 19→};
 20→
 21→/// Hex-encode bytes without pulling in the `hex` crate.
 22→fn hex_encode(bytes: &[u8]) -> String {
 23→    let mut s = String::with_capacity(bytes.len() * 2);
 24→    for b in bytes {
 25→        let _ = write!(s, "{b:02x}");
 26→    }
 27→    s
 28→}
 29→
 30→/// In-memory store implementing all wacore storage traits.
 31→#[derive(Clone, Default)]
 32→pub struct MemoryStore {
 33→    identities: Arc<DashMap<String, Vec<u8>>>,
 34→    sessions: Arc<DashMap<String, Vec<u8>>>,
 35→    prekeys: Arc<DashMap<u32, (Vec<u8>, bool)>>,
 36→    signed_prekeys: Arc<DashMap<u32, Vec<u8>>>,
 37→    sender_keys: Arc<DashMap<String, Vec<u8>>>,
 38→    sync_keys: Arc<DashMap<Vec<u8>, AppStateSyncKey>>,
 39→    app_state_versions: Arc<DashMap<String, HashState>>,
 40→    /// Keyed by `"{name}:{version}:{hex(index_mac)}"`.
 41→    mutation_macs: Arc<DashMap<String, Vec<u8>>>,
 42→    /// Keyed by `"{name}:{version}"` → list of index_macs stored at that version.
 43→    mutation_mac_indexes: Arc<DashMap<String, Vec<Vec<u8>>>>,
 44→    device_data: Arc<tokio::sync::RwLock<Option<wacore::store::Device>>>,
 45→    device_id: Arc<std::sync::atomic::AtomicI32>,
 46→    skdm_recipients: Arc<DashMap<String, Vec<String>>>,
 47→    lid_mappings: Arc<DashMap<String, LidPnMappingEntry>>,
 48→    /// Phone number → LID reverse index.
 49→    pn_mappings: Arc<DashMap<String, String>>,
 50→    device_list_records: Arc<DashMap<String, DeviceListRecord>>,
 51→    /// Keyed by `"{group_jid}:{participant}"`.
 52→    sender_key_forget_marks: Arc<DashMap<String, bool>>,
 53→    /// Base keys keyed by `"{address}:{message_id}"`.
 54→    base_keys: Arc<DashMap<String, Vec<u8>>>,
 55→}
 56→
 57→impl MemoryStore {
 58→    pub fn new() -> Self {
 59→        Self::default()
 60→    }
 61→}
 62→
 63→// ============================================================================
 64→// SignalStore
 65→// ============================================================================
 66→
 67→#[async_trait]
 68→impl SignalStore for MemoryStore {
 69→    async fn put_identity(&self, address: &str, key: [u8; 32]) -> Result<()> {
 70→        self.identities.insert(address.to_string(), key.to_vec());
 71→        Ok(())
 72→    }
 73→
 74→    async fn load_identity(&self, address: &str) -> Result<Option<Vec<u8>>> {
 75→        Ok(self.identities.get(address).map(|v| v.value().clone()))
 76→    }
 77→
 78→    async fn delete_identity(&self, address: &str) -> Result<()> {
 79→        self.identities.remove(address);
 80→        Ok(())
 81→    }
 82→
 83→    async fn get_session(&self, address: &str) -> Result<Option<Vec<u8>>> {
 84→        Ok(self.sessions.get(address).map(|v| v.value().clone()))
 85→    }
 86→
 87→    async fn put_session(&self, address: &str, session: &[u8]) -> Result<()> {
 88→        self.sessions.insert(address.to_string(), session.to_vec());
 89→        Ok(())
 90→    }
 91→
 92→    async fn delete_session(&self, address: &str) -> Result<()> {
 93→        self.sessions.remove(address);
 94→        Ok(())
 95→    }
 96→
 97→    async fn store_prekey(&self, id: u32, record: &[u8], uploaded: bool) -> Result<()> {
 98→        self.prekeys.insert(id, (record.to_vec(), uploaded));
 99→        Ok(())
100→    }
101→
102→    async fn load_prekey(&self, id: u32) -> Result<Option<Vec<u8>>> {
103→        Ok(self.prekeys.get(&id).map(|v| v.value().0.clone()))
104→    }
105→
106→    async fn remove_prekey(&self, id: u32) -> Result<()> {
107→        self.prekeys.remove(&id);
108→        Ok(())
109→    }
110→
111→    async fn store_signed_prekey(&self, id: u32, record: &[u8]) -> Result<()> {
112→        self.signed_prekeys.insert(id, record.to_vec());
113→        Ok(())
114→    }
115→
116→    async fn load_signed_prekey(&self, id: u32) -> Result<Option<Vec<u8>>> {
117→        Ok(self.signed_prekeys.get(&id).map(|v| v.value().clone()))
118→    }
119→
120→    async fn load_all_signed_prekeys(&self) -> Result<Vec<(u32, Vec<u8>)>> {
121→        Ok(self
122→            .signed_prekeys
123→            .iter()
124→            .map(|e| (*e.key(), e.value().clone()))
125→            .collect())
126→    }
127→
128→    async fn remove_signed_prekey(&self, id: u32) -> Result<()> {
129→        self.signed_prekeys.remove(&id);
130→        Ok(())
131→    }
132→
133→    async fn put_sender_key(&self, address: &str, record: &[u8]) -> Result<()> {
134→        self.sender_keys
135→            .insert(address.to_string(), record.to_vec());
136→        Ok(())
137→    }
138→
139→    async fn get_sender_key(&self, address: &str) -> Result<Option<Vec<u8>>> {
140→        Ok(self.sender_keys.get(address).map(|v| v.value().clone()))
141→    }
142→
143→    async fn delete_sender_key(&self, address: &str) -> Result<()> {
144→        self.sender_keys.remove(address);
145→        Ok(())
146→    }
147→}
