269→#[async_trait]
270→impl ChannelStreamOutbound for WhatsAppOutbound {
271→    async fn send_stream(
272→        &self,
273→        account_id: &str,
274→        to: &str,
275→        reply_to: Option<&str>,
276→        mut stream: StreamReceiver,
277→    ) -> ChannelResult<()> {
278→        // WhatsApp doesn't support message editing, so collect all deltas
279→        // and send the final text as a single message.
280→        let mut text = String::new();
281→        while let Some(event) = stream.recv().await {
282→            match event {
283→                StreamEvent::Delta(delta) => text.push_str(&delta),
284→                StreamEvent::Done => break,
285→                StreamEvent::Error(err) => {
286→                    debug!(account_id, chat_id = to, "WhatsApp stream error: {err}");
287→                    if text.is_empty() {
288→                        text = err;
289→                    }
290→                    break;
291→                },
292→            }
293→        }
294→        if text.is_empty() {
295→            return Ok(());
296→        }
297→        self.send_text(account_id, to, &text, reply_to).await
298→    }
299→
300→    async fn is_stream_enabled(&self, _account_id: &str) -> bool {
301→        false
302→    }
