use std::sync::{Arc, atomic::Ordering};

use {
    tracing::{debug, info, warn},
    wacore::types::{events::Event, message::MessageInfo},
    wacore_binary::jid::{Jid, JidExt as _},
    waproto::whatsapp as wa,
    whatsapp_rust::client::Client,
};

use moltis_channels::{
    ChannelAttachment, ChannelEvent, ChannelMessageKind, ChannelMessageMeta, ChannelReplyTarget,
    ChannelType,
    config_view::ChannelConfigView,
    message_log::MessageLogEntry,
    otp::{approve_sender_via_otp, emit_otp_challenge, emit_otp_resolution},
};

use crate::{
    access::{self, AccessDenied},
    config::WhatsAppAccountConfig,
    otp::{OTP_CHALLENGE_MSG, OtpInitResult, OtpVerifyResult},
    state::{AccountState, AccountStateMap, has_bot_watermark},
};

fn mirror_connected(accounts: &AccountStateMap, account_id: &str, connected: bool) {
    let map = accounts.read().unwrap_or_else(|e| e.into_inner());
    if let Some(state) = map.get(account_id) {
        state.connected.store(connected, Ordering::Relaxed);
    }
}

fn mirror_latest_qr(accounts: &AccountStateMap, account_id: &str, qr: Option<String>) {
    let mut map = accounts.write().unwrap_or_else(|e| e.into_inner());
    if let Some(state) = map.get_mut(account_id)
        && let Ok(mut latest_qr) = state.latest_qr.write()
    {
        *latest_qr = qr;
    }
}

fn current_config(
    accounts: &AccountStateMap,
    account_id: &str,
    fallback: &WhatsAppAccountConfig,
) -> WhatsAppAccountConfig {
    let map = accounts.read().unwrap_or_else(|e| e.into_inner());
    map.get(account_id)
        .map(|s| s.config.clone())
        .unwrap_or_else(|| fallback.clone())
}

/// Process an incoming whatsapp-rust event for the given account.
pub async fn handle_event(
    event: Event,
    client: Arc<Client>,
    state: Arc<AccountState>,
    accounts: AccountStateMap,
) {
    match event {
        Event::PairingQrCode { code, .. } => {
            info!(account_id = %state.account_id, "QR code generated for pairing");

            // Store latest QR data so the REST endpoint can serve it.
            if let Ok(mut qr) = state.latest_qr.write() {
                *qr = Some(code.clone());
            }
            mirror_latest_qr(&accounts, &state.account_id, Some(code.clone()));

            if let Some(ref sink) = state.event_sink {
                sink.emit(ChannelEvent::PairingQrCode {
                    channel_type: ChannelType::Whatsapp,
                    account_id: state.account_id.clone(),
                    qr_data: code,
                })
                .await;
            }
        },
        Event::Connected(_) => {
            info!(account_id = %state.account_id, "WhatsApp connected");
            state.connected.store(true, Ordering::Relaxed);
            mirror_connected(&accounts, &state.account_id, true);

            // Clear QR data once connected.
            if let Ok(mut qr) = state.latest_qr.write() {
                *qr = None;
            }
            mirror_latest_qr(&accounts, &state.account_id, None);

            let display_name = state.client.get_push_name().await;
            let display = if display_name.is_empty() {
                None
            } else {
                Some(display_name)
            };

            if let Some(ref sink) = state.event_sink {
                sink.emit(ChannelEvent::PairingComplete {
                    channel_type: ChannelType::Whatsapp,
                    account_id: state.account_id.clone(),
                    display_name: display,
                })
                .await;
            }
        },
        Event::PairError(err) => {
            warn!(account_id = %state.account_id, error = ?err, "WhatsApp pairing failed");
            if let Some(ref sink) = state.event_sink {
                sink.emit(ChannelEvent::PairingFailed {
                    channel_type: ChannelType::Whatsapp,
                    account_id: state.account_id.clone(),
                    reason: format!("{err:?}"),
                })
                .await;
            }
        },
        Event::Disconnected(_) => {
            info!(account_id = %state.account_id, "WhatsApp disconnected");
            state.connected.store(false, Ordering::Relaxed);
            mirror_connected(&accounts, &state.account_id, false);
        },
        Event::LoggedOut(_) => {
            warn!(account_id = %state.account_id, "WhatsApp logged out");
            state.connected.store(false, Ordering::Relaxed);
            mirror_connected(&accounts, &state.account_id, false);
            if let Some(ref sink) = state.event_sink {
                sink.emit(ChannelEvent::AccountDisabled {
                    channel_type: ChannelType::Whatsapp,
                    account_id: state.account_id.clone(),
                    reason: "logged out by WhatsApp".into(),
                })
                .await;
            }
        },
        Event::Message(msg, msg_info) => {
            handle_message(msg, msg_info, &client, &state, &accounts).await;
        },
        _ => {
            debug!(account_id = %state.account_id, event = ?std::mem::discriminant(&event), "unhandled WhatsApp event");
        },
    }
}

async fn handle_message(
    msg: Box<wa::Message>,
    info: MessageInfo,
    client: &Client,
    state: &AccountState,
    accounts: &AccountStateMap,
) {
    #[cfg(feature = "metrics")]
    moltis_metrics::counter!(
        moltis_metrics::channels::MESSAGES_RECEIVED_TOTAL,
        moltis_metrics::labels::CHANNEL => "whatsapp"
    )
    .increment(1);

    let sender_jid: &Jid = &info.source.sender;
    let chat_jid: &Jid = &info.source.chat;

    let peer_id = sender_jid.to_string();
    let chat_id = chat_jid.to_string();
    let username = sender_jid.user.clone();
    let sender_name = if info.push_name.is_empty() {
        None
    } else {
        Some(info.push_name.clone())
    };

    if should_ignore_inbound_chat(&info.source) {
        debug!(
            account_id = %state.account_id,
            chat = %chat_jid,
            sender = %sender_jid,
            "ignoring WhatsApp status/broadcast traffic"
        );
        return;
    }

    // Self-chat detection:
    // - Primary path: `is_from_me` (message sent from another device on our own account).
    // - Fallback path: sender/chat JIDs match the linked account owner.
    //
    // Some "Message Yourself" deliveries can arrive without `is_from_me = true`
    // but still use owner JIDs. Those should still bypass access control.
    //
    // We still prevent loops by dropping known bot echoes (recent sent IDs
    // and watermark).
    let mut is_owner_self_chat = false;
    let own_pn = state.client.get_pn().await;
    let own_lid = state.client.get_lid().await;
    let is_self_chat = is_owner_user(chat_jid, own_pn.as_ref(), own_lid.as_ref());
    let sender_is_owner = is_owner_user(sender_jid, own_pn.as_ref(), own_lid.as_ref());

    if info.source.is_from_me || (is_self_chat && sender_is_owner) {
        // Check text for bot watermark as secondary loop detection.
        let raw_text = msg
            .conversation
            .as_deref()
            .or_else(|| {

content.content:
200→            .or_else(|| {
201→                msg.extended_text_message
202→                    .as_ref()
203→                    .and_then(|m| m.text.as_deref())
204→            })
205→            .unwrap_or("");
206→
207→        if !is_self_chat || state.was_sent_by_us(&info.id) || has_bot_watermark(raw_text) {
208→            debug!(
209→                account_id = %state.account_id,
210→                is_self_chat,
211→                sender_is_owner,
212→                is_from_me = info.source.is_from_me,
213→                "ignoring self-sent message"
214→            );
215→            return;
216→        }
217→        debug!(
218→            account_id = %state.account_id,
219→            sender_is_owner,
220→            is_from_me = info.source.is_from_me,
221→            "processing self-chat message from another device"
222→        );
223→        is_owner_self_chat = true;
224→    }
225→
226→    // Extract text from the message.
227→    let text = msg
228→        .conversation
229→        .as_deref()
230→        .or_else(|| {
231→            msg.extended_text_message
232→                .as_ref()
233→                .and_then(|m| m.text.as_deref())
234→        })
235→        .unwrap_or("");
236→
237→    let message_kind = classify_message(&msg, text);
238→    let effective_config = current_config(accounts, &state.account_id, &state.config);
239→
240→    // Access control. Self-chat messages from the account owner always bypass
241→    // access control — the owner is inherently authorized.
242→    let is_group = info.source.is_group;
243→    let group_id = if is_group {
244→        Some(chat_id.as_str())
245→    } else {
246→        None
247→    };
248→    let bot_mentioned = if is_group {
249→        message_mentions_owner(&msg, own_pn.as_ref(), own_lid.as_ref())
250→    } else {
251→        false
252→    };
253→    let access_result = if is_owner_self_chat {
254→        Ok(())
255→    } else {
256→        access::check_access(
257→            &effective_config,
258→            is_group,
259→            &peer_id,
260→            Some(&username),
261→            group_id,
262→            bot_mentioned,
263→        )
264→    };
265→    let access_granted = access_result.is_ok();
266→
267→    // Log the message (with access_granted reflecting the actual check).
268→    if let Some(ref log) = state.message_log {
269→        let now = std::time::SystemTime::now()
270→            .duration_since(std::time::UNIX_EPOCH)
271→            .unwrap_or_default()
272→            .as_secs() as i64;
273→        let entry = MessageLogEntry {
274→            id: 0,
275→            account_id: state.account_id.clone(),
276→            channel_type: ChannelType::Whatsapp.to_string(),
277→            peer_id: peer_id.clone(),
278→            username: Some(username.clone()),
279→            sender_name: sender_name.clone(),
280→            chat_id: chat_id.clone(),
281→            chat_type: if is_group {
282→                "group"
283→            } else {
284→                "private"
285→            }
286→            .into(),
287→            body: text.to_string(),
288→            access_granted,
289→            created_at: now,
290→        };
291→        if let Err(e) = log.log(entry).await {
292→            warn!(account_id = %state.account_id, "failed to log message: {e}");
293→        }
294→    }
295→
296→    // Emit inbound message event.
297→    if let Some(ref sink) = state.event_sink {
298→        sink.emit(ChannelEvent::InboundMessage {
299→            channel_type: ChannelType::Whatsapp,
300→            account_id: state.account_id.clone(),
301→            peer_id: peer_id.clone(),
302→            username: Some(username.clone()),
303→            sender_name: sender_name.clone(),
304→            message_count: None,
305→            access_granted,
306→        })
307→        .await;
308→    }
309→
310→    // Handle access denial.
311→    if let Err(reason) = access_result {
312→        warn!(
313→            account_id = %state.account_id,
314→            %reason,
315→            peer_id,
316→            username,
317→            "access denied"
318→        );
