 525→/// Handle an inbound voice/audio message: download, transcribe (STT), dispatch as text.
 526→#[allow(clippy::too_many_arguments)]
 527→async fn handle_voice_audio(
 528→    msg: &wa::Message,
 529→    client: &Client,
 530→    account_id: &str,
 531→    kind: ChannelMessageKind,
 532→    reply_to: ChannelReplyTarget,
 533→    meta: ChannelMessageMeta,
 534→    chat_jid: &Jid,
 535→    state: &AccountState,
 536→) {
 537→    let Some(ref audio) = msg.audio_message else {
 538→        return;
 539→    };
 540→
 541→    // Determine format from MIME type.
 542→    let format = audio
 543→        .mimetype
 544→        .as_deref()
 545→        .map(|m| match m {
 546→            "audio/ogg" | "audio/ogg; codecs=opus" => "ogg",
 547→            "audio/mpeg" | "audio/mp3" => "mp3",
 548→            "audio/mp4" | "audio/m4a" | "audio/x-m4a" | "audio/aac" => "m4a",
 549→            "audio/wav" | "audio/x-wav" => "wav",
 550→            "audio/webm" => "webm",
 551→            _ => "ogg", // WhatsApp voice messages default to OGG Opus
 552→        })
 553→        .unwrap_or("ogg")
 554→        .to_string();
 555→
 556→    let kind_label = if matches!(kind, ChannelMessageKind::Voice) {
 557→        "voice"
 558→    } else {
 559→        "audio"
 560→    };
 561→
 562→    // Check STT availability.
 563→    let stt_available = if let Some(ref sink) = state.event_sink {
 564→        sink.voice_stt_available().await
 565→    } else {
 566→        false
 567→    };
 568→
 569→    if !stt_available {
 570→        // No STT — send a guidance message.
 571→        let reply_msg = wa::Message {
 572→            conversation: Some(format!(
 573→                "I received your {kind_label} message but voice transcription is not available. Please send a text message instead."
 574→            )),
 575→            ..Default::default()
 576→        };
 577→        let _ = state.send_message(chat_jid.clone(), reply_msg).await;
 578→        return;
 579→    }
 580→
 581→    match client.download(audio.as_ref()).await {
 582→        Ok(audio_data) => {
 583→            debug!(account_id, size = audio_data.len(), %format, kind_label, "downloaded WhatsApp audio");
 584→
 585→            if let Some(ref sink) = state.event_sink {
 586→                match sink.transcribe_voice(&audio_data, &format).await {
 587→                    Ok(transcribed) => {
 588→                        sink.dispatch_to_chat(&transcribed, reply_to, meta).await;
 589→                    },
 590→                    Err(e) => {
 591→                        warn!(account_id, error = %e, "voice transcription failed");
 592→                        let fallback = format!(
 593→                            "[{} message - transcription failed]",
 594→                            capitalize(kind_label)
 595→                        );
 596→                        sink.dispatch_to_chat(&fallback, reply_to, meta).await;
 597→                    },
 598→                }
 599→            }
 600→        },
 601→        Err(e) => {
 602→            warn!(account_id, error = %e, "failed to download WhatsApp audio");
 603→            let reply_msg = wa::Message {
 604→                conversation: Some(format!(
 605→                    "I received your {kind_label} message but couldn't download the audio. Please try again."
 606→                )),
 607→                ..Default::default()
 608→            };
 609→            let _ = state.send_message(chat_jid.clone(), reply_msg).await;
 610→        },
 611→    }
 612→}
