 696→/// Handle an inbound location or live location message.
 697→async fn handle_location(
 698→    msg: &wa::Message,
 699→    account_id: &str,
 700→    reply_to: ChannelReplyTarget,
 701→    meta: ChannelMessageMeta,
 702→    chat_jid: &Jid,
 703→    state: &AccountState,
 704→) {
 705→    // Check for static location first, then live location.
 706→    let (lat, lon, is_live) = if let Some(ref loc) = msg.location_message {
 707→        let lat = loc.degrees_latitude.unwrap_or(0.0);
 708→        let lon = loc.degrees_longitude.unwrap_or(0.0);
 709→        let is_live = loc.is_live.unwrap_or(false);
 710→        (lat, lon, is_live)
 711→    } else if let Some(ref loc) = msg.live_location_message {
 712→        let lat = loc.degrees_latitude.unwrap_or(0.0);
 713→        let lon = loc.degrees_longitude.unwrap_or(0.0);
 714→        (lat, lon, true)
 715→    } else {
 716→        return;
 717→    };
 718→
 719→    // Try to resolve a pending tool-triggered location request.
 720→    let resolved = if let Some(ref sink) = state.event_sink {
 721→        sink.update_location(&reply_to, lat, lon).await
 722→    } else {
 723→        false
 724→    };
 725→
 726→    if resolved {
 727→        let confirmation = wa::Message {
 728→            conversation: Some("Location updated.".into()),
 729→            ..Default::default()
 730→        };
 731→        if let Err(e) = state.send_message(chat_jid.clone(), confirmation).await {
 732→            warn!(account_id, error = %e, "failed to send location confirmation");
 733→        }
 734→        return;
 735→    }
 736→
 737→    if is_live {
 738→        // Live location share — acknowledge silently. Subsequent updates will
 739→        // continue to try resolving pending tool requests.
 740→        debug!(account_id, lat, lon, "received live location update");
 741→        return;
 742→    }
 743→
 744→    // Static location — dispatch to the LLM.
 745→    let text = format!("I'm sharing my location: {lat}, {lon}");
 746→    if let Some(ref sink) = state.event_sink {
 747→        sink.dispatch_to_chat(&text, reply_to, meta).await;
 748→    }
 749→}
