 759→fn is_owner_user(jid: &Jid, own_pn: Option<&Jid>, own_lid: Option<&Jid>) -> bool {
 760→    own_pn.is_some_and(|pn| pn.is_same_user_as(jid))
 761→        || own_lid.is_some_and(|lid| lid.is_same_user_as(jid))
 762→}
