 764→fn context_info_mentions_owner(
 765→    context: Option<&wa::ContextInfo>,
 766→    own_pn: Option<&Jid>,
 767→    own_lid: Option<&Jid>,
 768→) -> bool {
 769→    context.is_some_and(|context| {
 770→        context.mentioned_jid.iter().any(|mentioned| {
 771→            mentioned
 772→                .parse::<Jid>()
 773→                .ok()
 774→                .is_some_and(|jid| is_owner_user(&jid, own_pn, own_lid))
 775→        })
 776→    })
 777→}
