 892→/// Handle OTP challenge/verification flow for a non-allowlisted DM user.
 893→///
 894→/// Called when `dm_policy = Allowlist`, the peer is not on the allowlist, and
 895→/// `otp_self_approval` is enabled.
 896→#[allow(clippy::too_many_arguments)]
 897→async fn handle_otp_flow(
 898→    accounts: &AccountStateMap,
 899→    account_id: &str,
 900→    peer_id: &str,
 901→    username: Option<&str>,
 902→    sender_name: Option<&str>,
 903→    body: &str,
 904→    chat_jid: &Jid,
 905→    state: &AccountState,
 906→) {
 907→    let has_pending = {
 908→        let accts = accounts.read().unwrap_or_else(|e| e.into_inner());
 909→        accts
 910→            .get(account_id)
 911→            .map(|s| {
 912→                let otp = s.otp.lock().unwrap_or_else(|e| e.into_inner());
 913→                otp.has_pending(peer_id)
 914→            })
 915→            .unwrap_or(false)
 916→    };
 917→
 918→    if has_pending {
 919→        let trimmed = body.trim();
 920→        if trimmed.len() != 6 || !trimmed.chars().all(|c| c.is_ascii_digit()) {
 921→            // Non-code message while OTP pending — silently ignore.
 922→            return;
 923→        }
 924→
 925→        let result = {
 926→            let accts = accounts.read().unwrap_or_else(|e| e.into_inner());
 927→            match accts.get(account_id) {
 928→                Some(s) => {
 929→                    let mut otp = s.otp.lock().unwrap_or_else(|e| e.into_inner());
 930→                    otp.verify(peer_id, trimmed)
 931→                },
 932→                None => return,
 933→            }
 934→        };
 935→
 936→        match result {
 937→            OtpVerifyResult::Approved => {
 938→                approve_sender_via_otp(
 939→                    state.event_sink.as_deref(),
 940→                    ChannelType::Whatsapp,
 941→                    account_id,
 942→                    peer_id,
 943→                    peer_id,
 944→                    username,
 945→                )
 946→                .await;
 947→
 948→                let reply = wa::Message {
 949→                    conversation: Some("Access granted! You can now use this bot.".into()),
 950→                    ..Default::default()
 951→                };
 952→                let _ = state.send_message(chat_jid.clone(), reply).await;
 953→            },
 954→            OtpVerifyResult::WrongCode { attempts_left } => {
 955→                let reply = wa::Message {
 956→                    conversation: Some(format!(
 957→                        "Wrong code. {attempts_left} attempt{} remaining.",
 958→                        if attempts_left == 1 {
 959→                            ""
 960→                        } else {
 961→                            "s"
 962→                        }
 963→                    )),
 964→                    ..Default::default()
 965→                };
 966→                let _ = state.send_message(chat_jid.clone(), reply).await;
 967→            },
 968→            OtpVerifyResult::LockedOut => {
 969→                let reply = wa::Message {
 970→                    conversation: Some("Too many failed attempts. Please try again later.".into()),
 971→                    ..Default::default()
 972→                };
 973→                let _ = state.send_message(chat_jid.clone(), reply).await;
 974→                emit_otp_resolution(
 975→                    state.event_sink.as_deref(),
 976→                    ChannelType::Whatsapp,
 977→                    account_id,
 978→                    peer_id,
 979→                    username,
 980→                    "locked_out",
 981→                )
 982→                .await;
 983→            },
 984→            OtpVerifyResult::Expired => {
 985→                let reply = wa::Message {
 986→                    conversation: Some(
 987→                        "Your code has expired. Please send any message to get a new code.".into(),
 988→                    ),
 989→                    ..Default::default()
 990→                };
 991→                let _ = state.send_message(chat_jid.clone(), reply).await;
 992→                emit_otp_resolution(
 993→                    state.event_sink.as_deref(),
 994→                    ChannelType::Whatsapp,
 995→                    account_id,
 996→                    peer_id,
 997→                    username,
 998→                    "expired",
 999→                )
1000→                .await;
1001→            },
1002→            OtpVerifyResult::NoPending => {},
1003→        }
1004→        return;
1005→    }
1006→
1007→    // No pending challenge — initiate one.
1008→    let init_result = {
1009→        let accts = accounts.read().unwrap_or_else(|e| e.into_inner());
1010→        match accts.get(account_id) {
1011→            Some(s) => {
1012→                let mut otp = s.otp.lock().unwrap_or_else(|e| e.into_inner());
1013→                otp.initiate(
1014→                    peer_id,
1015→                    username.map(String::from),
1016→                    sender_name.map(String::from),
1017→                )
1018→            },
1019→            None => return,
1020→        }
1021→    };
1022→
1023→    match init_result {
1024→        OtpInitResult::Created(code) => {
1025→            info!(account_id, peer_id, code, "OTP challenge issued");
1026→            let reply = wa::Message {
1027→                conversation: Some(OTP_CHALLENGE_MSG.to_string()),
1028→                ..Default::default()
1029→            };
1030→            let _ = state.send_message(chat_jid.clone(), reply).await;
1031→
1032→            // Compute expires_at as epoch seconds (5 minutes from now).
1033→            let expires_at = std::time::SystemTime::now()
1034→                .duration_since(std::time::UNIX_EPOCH)
1035→                .unwrap_or_default()
1036→                .as_secs() as i64
1037→                + 300;
1038→
1039→            emit_otp_challenge(
1040→                state.event_sink.as_deref(),
1041→                ChannelType::Whatsapp,
1042→                account_id,
1043→                peer_id,
1044→                username,
1045→                sender_name,
1046→                code,
1047→                expires_at,
1048→            )
1049→            .await;
1050→        },
1051→        OtpInitResult::AlreadyPending => {
1052→            // Resend the challenge message.
1053→            let reply = wa::Message {
1054→                conversation: Some(OTP_CHALLENGE_MSG.to_string()),
1055→                ..Default::default()
1056→            };
1057→            let _ = state.send_message(chat_jid.clone(), reply).await;
1058→        },
1059→        OtpInitResult::LockedOut => {
1060→            let reply = wa::Message {
1061→                conversation: Some("Too many failed attempts. Please try again later.".into()),
1062→                ..Default::default()
1063→            };
1064→            let _ = state.send_message(chat_jid.clone(), reply).await;
1065→        },
1066→    }
1067→}
