  9→/// Gateway-side onboarding service backed by `moltis_onboarding::service::LiveOnboardingService`.
 10→pub struct GatewayOnboardingService {
 11→    inner: moltis_onboarding::service::LiveOnboardingService,
 12→    session_metadata: Arc<moltis_sessions::metadata::SqliteSessionMetadata>,
 13→    agent_persona_store: Arc<crate::agent_persona::AgentPersonaStore>,
 14→    gateway_state: Arc<tokio::sync::OnceCell<Arc<crate::state::GatewayState>>>,
 15→}
 16→
 17→impl GatewayOnboardingService {
 18→    pub fn new(
 19→        inner: moltis_onboarding::service::LiveOnboardingService,
 20→        session_metadata: Arc<moltis_sessions::metadata::SqliteSessionMetadata>,
 21→        agent_persona_store: Arc<crate::agent_persona::AgentPersonaStore>,
 22→        gateway_state: Arc<tokio::sync::OnceCell<Arc<crate::state::GatewayState>>>,
 23→    ) -> Self {
 24→        Self {
 25→            inner,
 26→            session_metadata,
 27→            agent_persona_store,
 28→            gateway_state,
 29→        }
 30→    }
 31→
 32→    /// Create imported agents as Moltis agent personas.
 33→    ///
 34→    /// Skips agents that already exist or are the default ("main") agent.
 35→    #[cfg(feature = "openclaw-import")]
 36→    async fn create_imported_agents(
 37→        &self,
 38→        agents: &moltis_openclaw_import::agents::ImportedAgents,
 39→    ) -> Result<(), String> {
 40→        for agent in &agents.agents {
 41→            if agent.is_default {
 42→                continue;
 43→            }
 44→
 45→            // Skip if already exists
 46→            match self.agent_persona_store.get(&agent.moltis_id).await {
 47→                Ok(Some(_)) => {
 48→                    tracing::debug!(
 49→                        id = %agent.moltis_id,
 50→                        "openclaw import: agent already exists, skipping"
 51→                    );
 52→                    continue;
 53→                },
 54→                Err(e) => {
 55→                    tracing::warn!(
 56→                        id = %agent.moltis_id,
 57→                        error = %e,
 58→                        "openclaw import: failed to check agent existence"
 59→                    );
 60→                    continue;
 61→                },
 62→                Ok(None) => {},
 63→            }
 64→
 65→            let name = agent
 66→                .name
 67→                .clone()
 68→                .unwrap_or_else(|| agent.moltis_id.clone());
 69→
 70→            let params = crate::agent_persona::CreateAgentParams {
 71→                id: agent.moltis_id.clone(),
 72→                name,
 73→                emoji: None,
 74→                theme: agent.theme.clone(),
 75→                description: None,
 76→            };
 77→
 78→            match self.agent_persona_store.create(params).await {
 79→                Ok(_) => {
 80→                    tracing::info!(
 81→                        id = %agent.moltis_id,
 82→                        "openclaw import: created agent persona"
 83→                    );
 84→                },
 85→                Err(e) => {
 86→                    tracing::warn!(
 87→                        id = %agent.moltis_id,
 88→                        error = %e,
 89→                        "openclaw import: failed to create agent persona"
 90→                    );
 91→                },
 92→            }
 93→        }
 94→        Ok(())
 95→    }
 96→
 97→    #[cfg(feature = "openclaw-import")]
 98→    async fn sync_imported_sessions_to_sqlite(
 99→        &self,
100→        data_dir: &std::path::Path,
101→    ) -> Result<(), String> {
102→        let metadata_path = data_dir.join("sessions").join("metadata.json");
103→        if !metadata_path.is_file() {
104→            return Ok(());
105→        }
106→
107→        let legacy_metadata = moltis_sessions::metadata::SessionMetadata::load(metadata_path)
108→            .map_err(|e| format!("failed to load imported metadata.json: {e}"))?;
109→
110→        for entry in legacy_metadata.list() {
111→            self.session_metadata
112→                .upsert(&entry.key, entry.label.clone())
113→                .await
114→                .map_err(|e| format!("failed to upsert session '{}': {e}", entry.key))?;
115→
116→            self.session_metadata
117→                .set_model(&entry.key, entry.model.clone())
118→                .await;
119→            self.session_metadata
120→                .set_project_id(&entry.key, entry.project_id.clone())
121→                .await;
122→            self.session_metadata
123→                .set_sandbox_enabled(&entry.key, entry.sandbox_enabled)
124→                .await;
125→            self.session_metadata
126→                .set_sandbox_image(&entry.key, entry.sandbox_image.clone())
127→                .await;
128→            self.session_metadata
129→                .set_worktree_branch(&entry.key, entry.worktree_branch.clone())
130→                .await;
131→            self.session_metadata
132→                .set_channel_binding(&entry.key, entry.channel_binding.clone())
133→                .await;
134→            self.session_metadata
135→                .set_parent(
136→                    &entry.key,
137→                    entry.parent_session_key.clone(),
138→                    entry.fork_point,
139→                )
140→                .await;
141→            self.session_metadata
142→                .set_mcp_disabled(&entry.key, entry.mcp_disabled)
143→                .await;
144→            if let Err(e) = self
145→                .session_metadata
146→                .set_agent_id(&entry.key, entry.agent_id.as_deref())
147→                .await
148→            {
149→                tracing::warn!(
150→                    key = %entry.key,
151→                    error = %e,
152→                    "openclaw import: failed to set agent_id on session"
153→                );
154→            }
155→            self.session_metadata
156→                .set_preview(&entry.key, entry.preview.as_deref())
157→                .await;
158→            self.session_metadata
159→                .set_timestamps_and_counts(
160→                    &entry.key,
161→                    entry.created_at,
162→                    entry.updated_at,
163→                    entry.message_count,
164→                    entry.last_seen_message_count,
165→                )
166→                .await;
167→        }
168→
169→        Ok(())
170→    }
171→}
