  8→export var MATRIX_DOCS_URL = "https://docs.moltis.org/matrix.html";
  9→export var MATRIX_DEFAULT_HOMESERVER = "https://matrix.org";
 10→export var MATRIX_ENCRYPTION_GUIDANCE =
 11→	"Encrypted Matrix chats require Password auth. Access token auth can connect for plain Matrix traffic, but it reuses an existing Matrix session without that device's private encryption keys, so Moltis cannot reliably decrypt encrypted chats. Use Password so Moltis creates and persists its own Matrix device keys, then finish Element verification in the same Matrix DM or room by sending `verify yes`, `verify no`, `verify show`, or `verify cancel` as normal chat messages.";
 12→export function matrixAuthModeGuidance(authMode) {
 13→	return normalizeMatrixAuthMode(authMode) === "password"
 14→		? "Required for encrypted Matrix chats. Moltis logs in as its own Matrix device and stores the device's encryption keys locally."
 15→		: "Does not support encrypted Matrix chats. Access tokens authenticate an existing Matrix session, but they do not transfer that device's private encryption keys into Moltis.";
 16→}
 17→export function channelStorageNote() {
 18→	var dbPath = String(getGon("channel_storage_db_path") || "").trim();
 19→	if (dbPath) {
