 33→export function validateChannelFields(type, accountId, credential, options = {}) {
 34→	if (!accountId.trim()) {
 35→		return { valid: false, error: "Account ID is required." };
 36→	}
 37→	if (!credential.trim()) {
 38→		if (type === "matrix") {
 39→			return { valid: false, error: matrixCredentialError(options.matrixAuthMode) };
 40→		}
 41→		return {
 42→			valid: false,
 43→			error: type === "msteams" ? "App password is required." : "Bot token is required.",
 44→		};
 45→	}
 46→	if (
 47→		type === "matrix" &&
 48→		normalizeMatrixAuthMode(options.matrixAuthMode) === "password" &&
 49→		!String(options.matrixUserId || "").trim()
 50→	) {
 51→		return { valid: false, error: "Matrix user ID is required for password login." };
 52→	}
 53→	return { valid: true };
 54→}
