145→/**
146→ * Parse an optional advanced channel config JSON object.
147→ * @param {string | null | undefined} text
148→ * @returns {{ ok: true, value: Record<string, unknown> } | { ok: false, error: string }}
149→ */
150→export function parseChannelConfigPatch(text) {
151→	var raw = String(text || "").trim();
152→	if (!raw) return { ok: true, value: {} };
153→	try {
154→		var value = JSON.parse(raw);
155→		if (!(value && typeof value === "object" && !Array.isArray(value))) {
156→			return { ok: false, error: "Advanced config must be a JSON object." };
157→		}
158→		return { ok: true, value };
159→	} catch (error) {
160→		var message = error instanceof Error ? error.message : String(error || "unknown error");
161→		return { ok: false, error: `Advanced config JSON is invalid: ${message}` };
162→	}
163→}
