214→export function generateWebhookSecretHex() {
215→	if (typeof window !== "undefined" && window.crypto?.getRandomValues) {
216→		var bytes = new Uint8Array(24);
217→		window.crypto.getRandomValues(bytes);
218→		return Array.from(bytes, (b) => b.toString(16).padStart(2, "0")).join("");
219→	}
220→	var value = "";
221→	while (value.length < 48) {
222→		value += Math.floor(Math.random() * 16).toString(16);
223→	}
224→	return value.slice(0, 48);
225→}
