100→// ── Connected client ─────────────────────────────────────────────────────────
101→
102→/// A WebSocket client currently connected to the gateway.
103→#[derive(Debug)]
104→pub struct ConnectedClient {
105→    pub conn_id: String,
106→    pub connect_params: ConnectParams,
107→    /// Bounded channel for sending serialized frames to this client's write loop.
108→    pub sender: mpsc::Sender<String>,
109→    pub connected_at: Instant,
110→    pub last_activity: Instant,
111→    /// The `Accept-Language` header from the WebSocket upgrade request, forwarded
112→    /// to web tools so fetched pages and search results match the user's locale.
113→    pub accept_language: Option<String>,
114→    /// The client's public IP address (extracted from proxy headers or direct
115→    /// connection). `None` when the client connects from a private/loopback address.
116→    pub remote_ip: Option<String>,
117→    /// The client's IANA timezone (e.g. `Europe/Lisbon`), sent by the browser
118→    /// via `Intl.DateTimeFormat().resolvedOptions().timeZone`.
119→    pub timezone: Option<String>,
120→    /// Event subscriptions (v4).
121→    /// `None` = wildcard (receive everything, v3 compat).
122→    /// `Some(set)` = only events in the set (or `"*"` = wildcard).
123→    pub subscriptions: Option<HashSet<String>>,
124→    /// Channels this client has joined (v4 multiplexing).
125→    pub joined_channels: HashSet<String>,
126→    /// Negotiated protocol version for this connection.
127→    pub negotiated_protocol: u32,
128→}
129→
130→impl ConnectedClient {
131→    pub fn role(&self) -> &str {
132→        self.connect_params.role.as_deref().unwrap_or("operator")
133→    }
134→
135→    pub fn scopes(&self) -> Vec<&str> {
136→        self.connect_params
137→            .scopes
138→            .as_ref()
139→            .map(|s| s.iter().map(|s| s.as_str()).collect())
140→            .unwrap_or_default()
141→    }
142→
143→    pub fn has_scope(&self, scope: &str) -> bool {
144→        self.scopes()
145→            .iter()
146→            .any(|s| *s == moltis_protocol::scopes::ADMIN || *s == scope)
147→    }
148→
149→    /// Check whether this client is subscribed to the given event.
150→    /// `None` subscriptions = wildcard (receive everything).
151→    pub fn is_subscribed_to(&self, event: &str) -> bool {
152→        match &self.subscriptions {
153→            None => true,
154→            Some(set) => {
155→                set.contains(moltis_protocol::subscriptions::WILDCARD) || set.contains(event)
156→            },
157→        }
158→    }
159→
160→    /// Check whether this client has joined the given channel.
161→    pub fn is_in_channel(&self, channel: &str) -> bool {
162→        self.joined_channels.contains(channel)
163→    }
164→
165→    /// Send a serialized JSON frame to this client.
166→    ///
167→    /// Uses `try_send` to avoid blocking; drops the frame if the client's
168→    /// outbound buffer is full (slow consumer protection).
169→    pub fn send(&self, frame: &str) -> bool {
170→        self.sender.try_send(frame.to_string()).is_ok()
171→    }
172→
173→    /// Touch the activity timestamp.
174→    pub fn touch(&mut self) {
175→        self.last_activity = Instant::now();
176→    }
177→}
