		${
			isApiKeyForm
				? html`<form onSubmit=${onSaveKey} class="flex flex-col gap-2 mt-3 border-t border-[var(--border)] pt-3">
				<div>
					<label class="text-xs text-[var(--muted)] mb-1 block">API Key</label>
