#[test]
fn agents_config_parses_presets() {
    let toml = r#"
[agents]
default_preset = "research"

[agents.presets.research]
model = "openai/gpt-5.2"
delegate_only = false
system_prompt_suffix = "Focus on evidence."
max_iterations = 10
timeout_secs = 120

[agents.presets.research.identity]
name = "scout"
