    #[tokio::test]
    async fn tc_token_expiry() {
        let store = temp_store();
        store
            .put_tc_token("old@lid", &TcTokenEntry {
                token: vec![1],
                token_timestamp: 100,
                sender_timestamp: None,
            })
            .await
            .unwrap();
        store
            .put_tc_token("new@lid", &TcTokenEntry {
                token: vec![2],
                token_timestamp: 2000,
